275	// parseDirectives parses a directive file into a slice of token slices.
276	// Lines starting with # are comments. Empty lines are skipped.
277	// Tokens are whitespace-separated; a quoted string in position 2+ is kept together.
278	func parseDirectives(content string) [][]string {
279		var out [][]string
280		scanner := bufio.NewScanner(strings.NewReader(content))
281		for scanner.Scan() {
282			line := strings.TrimSpace(scanner.Text())
283			if line == "" || strings.HasPrefix(line, "#") {
284				continue
285			}
286			tokens := splitDirective(line)
287			if len(tokens) == 0 {
288				continue
289			}
290			out = append(out, tokens)
291		}
292		return out
293	}
294	
295	// splitDirective splits a directive line into tokens.
296	// Returns [verb, arg1, arg2, ...] where the final argument absorbs any
297	// remaining whitespace-separated words as a single string. Surrounding
298	// double-quotes on the final argument are stripped.
299	//
300	// For directives that need 3 distinct args (modify-line: path regex repl)
301	// we return verb + 3 separate fields: parts[0..2], with parts[3:] joined
302	// onto the last field.
303	//
304	// The heuristic: each case in RunScript knows how many discrete args it
305	// needs and accesses them by index; the split just returns all fields, and
306	// the caller joins args[N:] for the "rest" argument.
307	func splitDirective(line string) []string {
308		// We need to preserve the raw fields so callers can pick the right number.
309		// Return all whitespace-split tokens; the final quoted token has quotes stripped.
310		parts := strings.Fields(line)
311		if len(parts) == 0 {
312			return nil
313		}
314		// Strip quotes from the last token if the entire last token is quoted.
315		last := parts[len(parts)-1]
316		if len(last) >= 2 && last[0] == '"' && last[len(last)-1] == '"' {
317			parts[len(parts)-1] = last[1 : len(last)-1]
318		}
319		return parts
320	}
